using NewSmartAIFactory.CompanyApi.Models;using NewSmartAIFactory.CompanyApi.Services;using Npgsql;
namespace NewSmartAIFactory.CompanyApi.Endpoints;
public static class ApprovalEndpoints{public static IEndpointRouteBuilder MapApprovalEndpoints(this IEndpointRouteBuilder app){var g=app.MapGroup("/api/approvals").WithTags("Approvals");g.MapGet("/",async(string? status,ApprovalWorkflowService s,CancellationToken t)=>Results.Ok(await s.ListAsync(status,t)));g.MapGet("/{id}",async(string id,ApprovalWorkflowService s,CancellationToken t)=>{var item=await s.GetAsync(id,t);return item is null?Results.NotFound():Results.Ok(item);});g.MapPost("/",async(CreateApprovalRequest r,ApprovalWorkflowService s,CancellationToken t)=>{if(string.IsNullOrWhiteSpace(r.ProjectId)||string.IsNullOrWhiteSpace(r.Title)||string.IsNullOrWhiteSpace(r.Description)||string.IsNullOrWhiteSpace(r.RequestedBy))return Results.BadRequest(new{error="required_fields",message="ProjectId, title, description, and requestedBy are required."});try{var id=await s.CreateAsync(r,t);return Results.Created($"/api/approvals/{id}",await s.GetAsync(id,t));}catch(PostgresException ex)when(ex.SqlState==PostgresErrorCodes.ForeignKeyViolation){return Results.BadRequest(new{error="project_not_found",message=$"Project '{r.ProjectId}' does not exist."});}});g.MapPost("/{id}/actions",async(string id,ApprovalActionRequest r,ApprovalWorkflowService s,CancellationToken t)=>{if(string.IsNullOrWhiteSpace(r.Actor))return Results.BadRequest(new{error="actor_required",message="Actor is required."});try{return await s.ActAsync(id,r,t)?Results.Ok(await s.GetAsync(id,t)):Results.NotFound();}catch(ArgumentException ex){return Results.BadRequest(new{error="invalid_action",message=ex.Message});}});return app;}}
